#!/usr/bin/env node
import fs from 'fs';
import path from 'path';

const ROOT = process.cwd();
const OUT_DIR = path.join(ROOT, 'assets', 'data', 'spec_subjects');

function concept(term, definition, caseText, action, hint, explanation){
  return { term, definition, caseText, action, hint, explanation };
}
function topic(id, nm, concepts, templates = 3){
  return { id, nm, concepts, templates };
}
function uniqueOptions(values, fallback){
  const out = [];
  for (const value of values) {
    const clean = String(value || '').trim();
    if (clean && !out.includes(clean)) out.push(clean);
  }
  for (const value of fallback) {
    const clean = String(value || '').trim();
    if (out.length >= 4) break;
    if (clean && !out.includes(clean)) out.push(clean);
  }
  return out.slice(0, 4);
}
function makeTopicQuestions(t){
  const fallbackTerms = ['Композиционный анализ', 'Техническое задание', 'Материаловедческий подход', 'Проектная гипотеза', 'Визуальная иерархия'];
  const fallbackActions = ['проверить цель решения и ограничения задачи', 'сравнить варианты по критериям качества', 'собрать референсы и оформить выводы', 'зафиксировать результат в проектной документации', 'провести короткую проверку на пользователе'];
  const questions = [];
  for (const c of t.concepts) {
    const wrongTerms = t.concepts.filter(x => x.term !== c.term).map(x => x.term);
    const wrongActions = t.concepts.filter(x => x.action !== c.action).map(x => x.action);
    questions.push({
      q: `Что лучше всего описывает понятие «${c.term}»: ${c.definition}?`,
      a: c.term,
      o: uniqueOptions([c.term, ...wrongTerms], fallbackTerms),
      h: c.hint,
      ex: c.explanation
    });
    questions.push({
      q: `Практический кейс: ${c.caseText} Какой термин здесь ключевой?`,
      a: c.term,
      o: uniqueOptions([c.term, ...wrongTerms.slice().reverse()], fallbackTerms),
      h: c.hint,
      ex: c.explanation
    });
    if (t.templates >= 3) {
      questions.push({
        q: `Какое действие лучше всего соответствует подходу «${c.term}»?`,
        a: c.action,
        o: uniqueOptions([c.action, ...wrongActions], fallbackActions),
        h: c.hint,
        ex: c.explanation
      });
    }
  }
  return questions;
}
function makeSubject({ id, nm, icon, desc, cl, bg, topics }){
  return {
    id, nm, icon, desc, cl, bg,
    tops: topics.map(t => ({ id: t.id, nm: t.nm, questions: makeTopicQuestions(t) }))
  };
}
function writeSubject(subject){
  fs.mkdirSync(OUT_DIR, { recursive: true });
  const file = path.join(OUT_DIR, `${subject.id}.json`);
  fs.writeFileSync(file, JSON.stringify(subject));
  return file;
}

