const result = subjects.map((subject) => {
  const file = writeSubject(subject);
  const topics = subject.tops.length;
  const questions = subject.tops.reduce((sum, t) => sum + t.questions.length, 0);
  return { id: subject.id, file: path.relative(ROOT, file), topics, questions };
});
